mapper.select:
SELECT PNO, QTY
FROM T_SCM_BARCODE
WHERE BARCODE = #{barcode}

mapper.update:
update t_scm_barcode
set laststatus = #{laststatus},
    lastfactory = #{factory},
    laststorage = #{storage}
where barcode = #{barcode}

mapper.select:
select a.iid, a.itemcode, to_number(a.qty) as qty, nvl(a.source,' ') as source, a.storage, substr(a.ymdhms,9,6) as time from t_wms_inbound a left outer join t_wms_location b on a.barcode = b.barcode and b.useyn ='Y' where a.sdate = #{date} and a.storage = #{storage}
and a.custcode = #{custcode}
and a.custname = #{custname}
and a.source = 'INCOMING' and a.factory = #{factory} and a.useyn = 'Y' order by a.ymdhms desc

SELECT
    a.sdate,
    a.factory,
    a.storage,
    a.itemcode,
    SUM(a.qty) as sumqty
FROM t_wms_inbound a
WHERE a.useyn = 'Y'
AND A.SOURCE = 'INCOMING'
AND a.sdate = #{date}
AND a.storage = #{storage}
AND a.factory = #{factory}

    AND a.custcode = #{custcode}


    AND a.custname = #{custname}

GROUP BY a.sdate, a.itemcode, a.factory, a.storage

SELECT a.sdate, c.subname AS car, a.itemcode, b.itemname, a.qty, a.type, a.barcode, a.location, ymdhms FROM t_wms_realstock a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode AND deldate = ' ' LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' where useyn = 'Y'
and a.sdate = #{sdate}
and factory = #{factory}
and storage = #{storage}
order by iid desc

SELECT a.SDATE, a.itemcode, a.STORAGE, a.FACTORY, SUM(a.QTY) as sumqty FROM T_WMS_REALSTOCK a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE a.useyn = 'Y'
and a.sdate = #{sdate}
and a.factory = #{factory}
and a.storage = #{storage}
and a.itemcode = #{itemCode}
GROUP BY a.SDATE, a.itemcode, a.STORAGE, a.FACTORY, a.scantype

SELECT DISTINCT STORAGE FROM T_WMS_WAREHOUSE
MEMO2 = #{type}
ORDER BY STORAGE
